import styles from './SignalHistory.module.css';

export default function SignalHistory({ history }) {
  return (
    <div className={styles.panel}>
      <div className={styles.title}>📋 Son Sinyaller</div>
      {history.length === 0 ? (
        <p className={styles.empty}>Henüz sinyal yok...</p>
      ) : (
        <ul className={styles.list}>
          {history.map(h => (
            <li key={h.id} className={styles.row}>
              <span className={styles.sym}>{h.sym}</span>
              <span className={`${styles.type} ${styles[h.type === 'AL' ? 'buy' : 'sell']}`}>
                {h.type}
              </span>
              <span className={`${styles.result} ${h.win ? styles.win : styles.loss}`}>
                {h.result}
              </span>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
